challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is experiencing a 'zombied session' failure, as described by the 'n3_data_plane_outage' causal chain. The N4 control interface appears healthy with active sessions, but the N3 data plane is internally non-functional, causing all GTP-U traffic to be dropped.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "From UPF container to the gNB's N3 IP address.",
          "expected_if_hypothesis_holds": "Clean RTT (< 5ms). This indicates the network path is healthy, pointing to an internal UPF issue (the 'zombie' state).",
          "falsifying_observation": "100% packet loss. This falsifies the 'internal fault' hypothesis and proves a network partition, supporting h3."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "Check for a listener on UDP port 2152 in the UPF container.",
          "expected_if_hypothesis_holds": "A process is listening on port 2152. This confirms the data plane process is running, but internally failing to process packets.",
          "falsifying_observation": "No process is listening on port 2152. This suggests the UPF's data plane process has crashed or failed to bind to its port, a more severe infrastructure fault."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "Get the gNB's outbound N3 GTP traffic counter (e.g., `gtp_pdu_tx_n3`).",
          "expected_if_hypothesis_holds": "The gNB's transmit counter for N3 GTP packets is high and increasing, proving that traffic is being sent but dropped by the UPF.",
          "falsifying_observation": "The gNB's transmit counter is zero. This would mean no traffic is being sent to the UPF, so the problem lies upstream of the UPF."
        }
      ],
      "notes": "This plan focuses on proving the UPF is the failure point by confirming N3 path health (discriminating from h3) and upstream activity."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The SMF is failing to correctly program the UPF over the N4 interface. While PFCP sessions exist, the specific forwarding rules may be missing or incorrect, causing the UPF to discard all user plane traffic.",
      "primary_suspect_nf": "smf",
      "probes": [
        {
          "tool": "get_nf_metrics",
          "args_hint": "Get SMF metrics for PFCP session modification failures (e.g., `smf_pfcp_modification_errors`).",
          "expected_if_hypothesis_holds": "PFCP error counters on the SMF are elevated, indicating it is aware of failures when programming the UPF.",
          "falsifying_observation": "All SMF-side PFCP counters are clean. This falsifies the hypothesis, as it shows the SMF believes it is programming the UPF successfully."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "Get UPF metrics for rejected N4 PFCP requests (e.g., `upf_pfcp_request_rejects`).",
          "expected_if_hypothesis_holds": "The UPF's PFCP rejection counter is zero, which would mean it is accepting the rules from the SMF, even if they are semantically incorrect.",
          "falsifying_observation": "The UPF's PFCP rejection counter is high. This would indicate an incompatibility or misconfiguration, shifting the fault from 'bad rules from SMF' to 'UPF actively rejecting rules'."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "Measure RTT from the SMF container to the UPF's N4 IP address.",
          "expected_if_hypothesis_holds": "Clean RTT (< 5ms), confirming the N4 control plane path is healthy.",
          "falsifying_observation": "100% packet loss. This would indicate an N4 network partition, a more fundamental issue than incorrect PFCP programming."
        }
      ],
      "notes": "This plan investigates the health of the N4 interface and the PFCP message exchange between the SMF and UPF."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "A network-level partition has severed the N3 interface path between the gNodeB and the UPF. Both components may be healthy, but a routing or firewall issue is preventing GTP-U packets from being exchanged.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "From UPF container to the gNB's N3 IP address.",
          "expected_if_hypothesis_holds": "100% packet loss, confirming the path is broken.",
          "falsifying_observation": "Clean RTT (< 5ms). This directly falsifies the hypothesis by proving the path is healthy."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "From gNB container to the UPF's N3 IP address.",
          "expected_if_hypothesis_holds": "100% packet loss, confirming the path is broken in the reverse direction.",
          "falsifying_observation": "Clean RTT (< 5ms). This would suggest a unidirectional network issue, but still falsifies a simple, complete partition."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "From UPF container to the SMF's N4 IP address.",
          "expected_if_hypothesis_holds": "Clean RTT (< 5ms). This shows the UPF's networking is working, isolating the problem to the N3 path.",
          "falsifying_observation": "100% packet loss. This would indicate a broader network issue where the UPF is completely isolated, not just a partitioned N3 interface."
        }
      ],
      "notes": "This plan uses bi-directional and triangulated RTT measurements to definitively prove or disprove a network partition on the N3 interface."
    }
  ]
}

